-- Additional sales_sku_map entries so 2026 sales match Spring 2027 plan items.
-- Generated by token-similarity matching on normalized size + description
-- (>=0.60 Jaccard with a clear margin over the runner-up). Ambiguous and
-- genuinely-absent SKUs are deliberately NOT included — those need a human.
on conflict (sku) do update set plan_item_name = excluded.plan_item_name, note = excluded.note;
